def build_device_points_map(devices: List[Dict], all_points: List[Dict]) -> Dict:
    """�����豸���ӳ��"""
    device_map = {}
    for device in devices:
        ins_id = device.get('insStandardId') or device.get('insId')
        device_map[ins_id] = {'a': None, 'b': None, 'c': None}
    
    for point in all_points:
        ins_standard_id = point.get('insStandardId')
        extends_name = point.get('extendsName', '')
        if not ins_standard_id:
            continue
        
        if extends_name == 'A_����_A':
            device_map[ins_standard_id]['a'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
        elif extends_name == 'B_����_A':
            device_map[ins_standard_id]['b'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
        elif extends_name == 'C_����_A':
            device_map[ins_standard_id]['c'] = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId')
            }
    return device_map

