        # 简单映射
        mapping = {
            '排名': 'rank', '序号': 'rank',
            '设备名称': 'ins_name', '名称': 'name',
            '楼层': 'floor',
            'A相': 'phase_a', 'A相电流': 'phase_a', 'A': 'phase_a',
