            return False

        import subprocess
        try:
            result = subprocess.run(
                ['docker-compose', 'up', '-d'],
                cwd=service_dir,
                capture_output=True,
                text=True,
                timeout=60
            )
            return result.returncode == 0
        except Exception as e:
            print(f"启动服务失败: {e}")
            return False

