        if point_mapping is None:
            point_mapping = {{ config.point_mapping or {} }}

        device_map = {}
        for device in devices:
            ins_id = device.get('insStandardId') or device.get('insId')
            device_map[ins_id] = {'A': None, 'B': None, 'C': None}

        for point in all_points:
            ins_standard_id = point.get('insStandardId')
            extends_name = point.get('extendsName', '')

            if not ins_standard_id or ins_standard_id not in device_map:
                continue

            point_info = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId'),
                'extends_name': extends_name
            }

            # 根据extendsName或point_mapping匹配相位
            if 'A' in extends_name or extends_name == point_mapping.get('A'):
                device_map[ins_standard_id]['A'] = point_info
            elif 'B' in extends_name or extends_name == point_mapping.get('B'):
                device_map[ins_standard_id]['B'] = point_info
            elif 'C' in extends_name or extends_name == point_mapping.get('C'):
