        # 3. 构建设备点位映射
        device_points_map = self._build_device_points_map(devices, all_points, point_mapping)

        # 4. 收集所有点位ID
        all_point_ids = []
        for ins_id, phases in device_points_map.items():
            for phase, point_info in phases.items():
                if point_info and point_info.get('ins_pt_id'):
                    all_point_ids.append(point_info['ins_pt_id'])

        # 5. 批量获取实时数据
        realtime_data = {}
        batch_size = 100
        for i in range(0, len(all_point_ids), batch_size):
            batch = all_point_ids[i:i+batch_size]
            batch_data = self.get_realtime_data(batch)
            if isinstance(batch_data, dict):
                realtime_data.update(batch_data)
            print(f"[INFO] 批量获取实时数据: {i+1}-{min(i+batch_size, len(all_point_ids))}/{len(all_point_ids)}")

        print(f"[INFO] 获取到 {len(realtime_data)} 条实时数据")

        return {
            'devices': devices,
            'points': all_points,
            'realtime': realtime_data,
            'device_points_map': device_points_map
        }

    def _build_device_points_map(self, devices: List[Dict], all_points: List[Dict],
                                  point_mapping: Dict[str, str] = None) -> Dict[str, Dict]:
        """构建设备点位映射"""
        if point_mapping is None:
            point_mapping = {{ config.point_mapping or {} }}

        device_map = {}
        for device in devices:
            ins_id = device.get('insStandardId') or device.get('insId')
            device_map[ins_id] = {'A': None, 'B': None, 'C': None}

        for point in all_points:
            ins_standard_id = point.get('insStandardId')
            extends_name = point.get('extendsName', '')

            if not ins_standard_id or ins_standard_id not in device_map:
                continue

            point_info = {
                'ins_pt_id': point.get('insPointStandardId'),
                'obj_pt_id': point.get('objPointDataId'),
                'extends_name': extends_name
            }

            # 根据extendsName或point_mapping匹配相位
            if 'A' in extends_name or extends_name == point_mapping.get('A'):
                device_map[ins_standard_id]['A'] = point_info
            elif 'B' in extends_name or extends_name == point_mapping.get('B'):
                device_map[ins_standard_id]['B'] = point_info
            elif 'C' in extends_name or extends_name == point_mapping.get('C'):
                device_map[ins_standard_id]['C'] = point_info

        return device_map

