        // 刷新数据
        async function refreshData() {
            const btn = document.getElementById('refreshBtn');
            btn.classList.add('spinning');
            btn.disabled = true;

            try {
                const response = await fetch('./api/data');
                const result = await response.json();

                if (result.success) {
                    abnormalData = result.devices;
