                        <div class="text-sm text-gray-300 mt-1">不平衡度≥40%设备存在严重负载不均<br>需立即安排检修</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">⚠️</span>
                    <div>
                        <div class="text-orange-400 font-semibold">重点关注 (${summary.focus_count || 0}台)</div>
                        <div class="text-sm text-gray-300 mt-1">不平衡度>15%设备<br>建议优化负载分配</div>
                    </div>
                </div>
                <div class="flex items-start gap-3">
                    <span class="text-2xl">📊</span>
                    <div>
                        <div class="text-cyan-400 font-semibold">整体评估 (${summary.valid_count || 0}台)</div>
                        <div class="text-sm text-gray-300 mt-1">平均不平衡度${summary.avg_unbalance || 0}%<br>异常率${summary.abnormal_pct || 0}%，需持续监控</div>
                    </div>
                </div>
            `;
        }

        // 获取楼层样式
        function getFloorClass(floor) {
            const floorMap = {
                'F1': 'floor-f1', 'F2': 'floor-f2', 'F3': 'floor-f3',
                'F4': 'floor-f4', 'F5': 'floor-f5', 'F6': 'floor-f6', 'F7': 'floor-f7'
            };
            return floorMap[floor] || 'floor-f1';
        }

        // 获取不平衡度样式
        function getUnbalanceClass(unbalance) {
            if (unbalance >= 40) return 'unbalance-critical';
            if (unbalance >= 30) return 'unbalance-high';
            if (unbalance >= 20) return 'unbalance-medium';
            return 'unbalance-normal';
        }

        // 获取排名样式
        function getRankClass(rank) {
            if (rank === 1) return 'rank-1';
            if (rank === 2) return 'rank-2';
            if (rank === 3) return 'rank-3';
            return 'rank-other';
        }

        // 更新表格
        function updateTable(devices) {
            const tbody = document.getElementById('abnormalTable');
            tbody.innerHTML = devices.map(item => `
                <tr>
                    <td><span class="rank-badge ${getRankClass(item.rank)}">${item.rank}</span></td>
                    <td class="font-medium text-white">${item.insName}</td>
                    <td><span class="floor-tag ${getFloorClass(item.floor)}">${item.floor}</span></td>
                    <td class="text-right text-cyan-300">${item.A}</td>
                    <td class="text-right text-cyan-300">${item.B}</td>
                    <td class="text-right text-cyan-300">${item.C}</td>
                    <td class="text-right font-mono">${item.total}</td>
                    <td class="text-right"><span class="unbalance-tag ${getUnbalanceClass(item.unbalance)}">${item.unbalance}%</span></td>
                </tr>
            `).join('');
        }

        // 导出Excel
        function exportToExcel() {
            const btn = document.getElementById('exportBtn');
            const originalContent = btn.innerHTML;
            btn.innerHTML = '<svg class="w-5 h-5 animate-spin" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg> 导出中...';
            btn.disabled = true;

            try {
                const wb = XLSX.utils.book_new();

                const wsData = [
                    ['序号', '设备名称', '楼层', 'A相电流(A)', 'B相电流(A)', 'C相电流(A)', '总电流(A)', '不平衡度(%)', '风险等级']
                ];

                abnormalData.forEach(item => {
                    let risk = '低';
                    if (item.unbalance >= 40) risk = '紧急';
                    else if (item.unbalance >= 30) risk = '高';
                    else if (item.unbalance >= 20) risk = '中';

                    wsData.push([
                        item.rank, item.insName, item.floor,
                        item.A, item.B, item.C, item.total,
                        item.unbalance, risk
                    ]);
                });

                const ws = XLSX.utils.aoa_to_sheet(wsData);
                ws['!cols'] = [
                    {wch: 6}, {wch: 28}, {wch: 8}, {wch: 14},
                    {wch: 14}, {wch: 14}, {wch: 12}, {wch: 14}, {wch: 10}
                ];

                XLSX.utils.book_append_sheet(wb, ws, '不平衡度异常设备');

                const fileName = `{{ title }}_异常设备清单_${new Date().toISOString().slice(0,10)}.xlsx`;
                XLSX.writeFile(wb, fileName);

                btn.innerHTML = '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"/></svg> 导出成功!';
                showToast('Excel导出成功', 'success');

                setTimeout(() => {
                    btn.innerHTML = originalContent;
                    btn.disabled = false;
                }, 2000);

            } catch (error) {
                console.error('导出失败:', error);
                showToast('导出失败: ' + error.message, 'error');
                btn.innerHTML = originalContent;
                btn.disabled = false;
            }
        }

        // 启动自动刷新
        function startAutoRefresh() {
            refreshTimer = setInterval(refreshData, REFRESH_INTERVAL);
        }

        // 页面可见性变化时处理
        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'visible') {
                refreshData();
                if (!refreshTimer) startAutoRefresh();
            } else {
                if (refreshTimer) {
                    clearInterval(refreshTimer);
                    refreshTimer = null;
                }
            }
        });

        // 初始化
        startAutoRefresh();
    </script>
</body>
</html>
